YapperAPI:RegisterDictionary("enBase", function()
    local d = {
        languageFamily = "en",
        words = {},
        phonetics = {},
    }
    local tinsert = table.insert
    for _, w in ipairs(getWords_0()) do tinsert(d.words, w) end
    for _, w in ipairs(getWords_1()) do tinsert(d.words, w) end
    for _, w in ipairs(getWords_2()) do tinsert(d.words, w) end
    for _, w in ipairs(getWords_3()) do tinsert(d.words, w) end
    for _, w in ipairs(getWords_4()) do tinsert(d.words, w) end
    for _, w in ipairs(getWords_5()) do tinsert(d.words, w) end
    for _, w in ipairs(getWords_6()) do tinsert(d.words, w) end
    for _, w in ipairs(getWords_7()) do tinsert(d.words, w) end
    for _, w in ipairs(getWords_8()) do tinsert(d.words, w) end
    for h, m in pairs(getPhonetics_0()) do d.phonetics[h] = m end
    for h, m in pairs(getPhonetics_1()) do d.phonetics[h] = m end
    for h, m in pairs(getPhonetics_2()) do d.phonetics[h] = m end
    for h, m in pairs(getPhonetics_3()) do d.phonetics[h] = m end
    for h, m in pairs(getPhonetics_4()) do d.phonetics[h] = m end
    for h, m in pairs(getPhonetics_5()) do d.phonetics[h] = m end
    return d
end)
